import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"伤寒杂病论","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/01-先秦两汉/02-伤寒杂病论.md","filePath":"tcm-data/01-先秦两汉/02-伤寒杂病论.md","lastUpdated":1781084559000}'),n={name:"tcm-data/01-先秦两汉/02-伤寒杂病论.md"};function r(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="伤寒杂病论" tabindex="-1">伤寒杂病论 <a class="header-anchor" href="#伤寒杂病论" aria-label="Permalink to &quot;伤寒杂病论&quot;">​</a></h1><blockquote><p>张仲景（约150-219年），东汉南阳人 医圣，&quot;辨证论治&quot;的创立者 后世分为《伤寒论》+《金匮要略》两部分</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：东汉末年（约公元200-210年）</li><li><strong>卷数</strong>：原书16卷，后因战乱散佚</li><li><strong>整理</strong>：西晋王叔和将原书分为《伤寒论》10卷 + 《金匮要略》3卷</li><li><strong>学术地位</strong>：中医四大经典之一，&quot;方书之祖&quot;，第一部理法方药完备的临床著作</li></ul><h3 id="写作背景" tabindex="-1">写作背景 <a class="header-anchor" href="#写作背景" aria-label="Permalink to &quot;写作背景&quot;">​</a></h3><p>东汉末年大疫，「余宗族素多，向余二百，建安纪元以来，犹未十稔，其死亡者，三分有二，伤寒十居其七。」仲景「感往昔之沦丧，伤横夭之莫救，乃勤求古训，博采众方。」</p><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-六经辨证-——-外感病的分类体系" tabindex="-1">1. 六经辨证 —— 外感病的分类体系 <a class="header-anchor" href="#_1-六经辨证-——-外感病的分类体系" aria-label="Permalink to &quot;1. 六经辨证 —— 外感病的分类体系&quot;">​</a></h3><blockquote><p><strong>张仲景以《内经》六经（三阴三阳）为纲，将外感病分为六个阶段：</strong></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">六经</th><th style="text-align:left;">脏腑归属</th><th style="text-align:left;">核心病机</th><th style="text-align:left;">提纲条文</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>太阳</strong></td><td style="text-align:left;">膀胱、小肠</td><td style="text-align:left;">外感初起，表证</td><td style="text-align:left;">「太阳之为病，脉浮，头项强痛而恶寒」</td></tr><tr><td style="text-align:left;"><strong>阳明</strong></td><td style="text-align:left;">胃、大肠</td><td style="text-align:left;">里实热证</td><td style="text-align:left;">「阳明之为病，胃家实是也」</td></tr><tr><td style="text-align:left;"><strong>少阳</strong></td><td style="text-align:left;">胆、三焦</td><td style="text-align:left;">半表半里</td><td style="text-align:left;">「少阳之为病，口苦、咽干、目眩也」</td></tr><tr><td style="text-align:left;"><strong>太阴</strong></td><td style="text-align:left;">脾、肺</td><td style="text-align:left;">里虚寒湿</td><td style="text-align:left;">「太阴之为病，腹满而吐，食不下，自利益甚」</td></tr><tr><td style="text-align:left;"><strong>少阴</strong></td><td style="text-align:left;">心、肾</td><td style="text-align:left;">全身虚衰</td><td style="text-align:left;">「少阴之为病，脉微细，但欲寐也」</td></tr><tr><td style="text-align:left;"><strong>厥阴</strong></td><td style="text-align:left;">肝、心包</td><td style="text-align:left;">寒热错杂</td><td style="text-align:left;">「厥阴之为病，消渴，气上撞心，心中疼热」</td></tr></tbody></table><h3 id="_2-辨证论治-——-中医临床的核心方法" tabindex="-1">2. 辨证论治 —— 中医临床的核心方法 <a class="header-anchor" href="#_2-辨证论治-——-中医临床的核心方法" aria-label="Permalink to &quot;2. 辨证论治 —— 中医临床的核心方法&quot;">​</a></h3><p><strong>八纲辨证</strong>（由后世发展，源于《伤寒论》的体系化）：</p><ul><li>表里：病位的深浅</li><li>寒热：病性的阴阳</li><li>虚实：正邪的强弱</li><li>阴阳：总纲</li></ul><h3 id="_3-六经传变规律" tabindex="-1">3. 六经传变规律 <a class="header-anchor" href="#_3-六经传变规律" aria-label="Permalink to &quot;3. 六经传变规律&quot;">​</a></h3><blockquote><p><strong>外感病的自然传变：太阳 → 阳明 → 少阳 → 太阴 → 少阴 → 厥阴</strong></p></blockquote><p>但也存在「合病」（两经同病）、「并病」（一经未罢，一经又起）等变化。</p><h3 id="_4-治法八法" tabindex="-1">4. 治法八法 <a class="header-anchor" href="#_4-治法八法" aria-label="Permalink to &quot;4. 治法八法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th><th style="text-align:left;">适应证</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>汗法</strong></td><td style="text-align:left;">麻黄汤、桂枝汤</td><td style="text-align:left;">表证（发汗解表）</td></tr><tr><td style="text-align:left;"><strong>吐法</strong></td><td style="text-align:left;">瓜蒂散</td><td style="text-align:left;">上焦痰实</td></tr><tr><td style="text-align:left;"><strong>下法</strong></td><td style="text-align:left;">承气汤类</td><td style="text-align:left;">里实证（攻下）</td></tr><tr><td style="text-align:left;"><strong>和法</strong></td><td style="text-align:left;">小柴胡汤</td><td style="text-align:left;">半表半里（和解）</td></tr><tr><td style="text-align:left;"><strong>温法</strong></td><td style="text-align:left;">四逆汤、理中丸</td><td style="text-align:left;">里虚寒（温阳）</td></tr><tr><td style="text-align:left;"><strong>清法</strong></td><td style="text-align:left;">白虎汤、黄连阿胶汤</td><td style="text-align:left;">里实热（清热）</td></tr><tr><td style="text-align:left;"><strong>补法</strong></td><td style="text-align:left;">炙甘草汤、小建中汤</td><td style="text-align:left;">虚证（补益）</td></tr><tr><td style="text-align:left;"><strong>消法</strong></td><td style="text-align:left;">桂枝茯苓丸、抵挡汤</td><td style="text-align:left;">瘀血、水饮、食积</td></tr></tbody></table><h3 id="_5-保胃气、存津液-——-治疗原则" tabindex="-1">5. 保胃气、存津液 —— 治疗原则 <a class="header-anchor" href="#_5-保胃气、存津液-——-治疗原则" aria-label="Permalink to &quot;5. 保胃气、存津液 —— 治疗原则&quot;">​</a></h3><blockquote><p><strong>「阴阳自和者，必自愈。」</strong></p></blockquote><p>仲景在治疗中极其重视：不伤胃气（中气为后天之本），不伤津液（阴液为阳气之根）。</p><hr><h2 id="三、代表方剂-精选20方" tabindex="-1">三、代表方剂（精选20方） <a class="header-anchor" href="#三、代表方剂-精选20方" aria-label="Permalink to &quot;三、代表方剂（精选20方）&quot;">​</a></h2><h3 id="太阳病方-表证" tabindex="-1">太阳病方（表证） <a class="header-anchor" href="#太阳病方-表证" aria-label="Permalink to &quot;太阳病方（表证）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝汤</strong></td><td style="text-align:left;">桂枝、芍药、甘草、生姜、大枣</td><td style="text-align:left;">太阳中风（有汗恶风）</td><td style="text-align:left;">感冒初期、自汗、过敏性鼻炎</td></tr><tr><td style="text-align:left;"><strong>麻黄汤</strong></td><td style="text-align:left;">麻黄、桂枝、杏仁、甘草</td><td style="text-align:left;">太阳伤寒（无汗恶寒）</td><td style="text-align:left;">流感、支气管炎初期</td></tr><tr><td style="text-align:left;"><strong>桂枝加葛根汤</strong></td><td style="text-align:left;">桂枝汤+葛根</td><td style="text-align:left;">项背强几几</td><td style="text-align:left;">颈椎病、落枕</td></tr><tr><td style="text-align:left;"><strong>麻杏石甘汤</strong></td><td style="text-align:left;">麻黄、杏仁、石膏、甘草</td><td style="text-align:left;">汗出而喘，无大热</td><td style="text-align:left;">肺炎、哮喘</td></tr></tbody></table><h3 id="阳明病方-里实热证" tabindex="-1">阳明病方（里实热证） <a class="header-anchor" href="#阳明病方-里实热证" aria-label="Permalink to &quot;阳明病方（里实热证）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>白虎汤</strong></td><td style="text-align:left;">石膏、知母、粳米、甘草</td><td style="text-align:left;">阳明经证，大热大渴大汗</td><td style="text-align:left;">中暑、高热、糖尿病</td></tr><tr><td style="text-align:left;"><strong>大承气汤</strong></td><td style="text-align:left;">大黄、芒硝、枳实、厚朴</td><td style="text-align:left;">阳明腑实（痞满燥实坚）</td><td style="text-align:left;">肠梗阻、便秘</td></tr></tbody></table><h3 id="少阳病方-半表半里" tabindex="-1">少阳病方（半表半里） <a class="header-anchor" href="#少阳病方-半表半里" aria-label="Permalink to &quot;少阳病方（半表半里）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">柴胡、黄芩、人参、半夏、甘草、生姜、大枣</td><td style="text-align:left;">少阳病，往来寒热</td><td style="text-align:left;">感冒反复、肝病、郁证</td></tr><tr><td style="text-align:left;"><strong>大柴胡汤</strong></td><td style="text-align:left;">小柴胡汤去人参甘草+大黄枳实芍药</td><td style="text-align:left;">少阳兼阳明</td><td style="text-align:left;">胆囊炎、胰腺炎</td></tr></tbody></table><h3 id="太阴病方-脾虚寒证" tabindex="-1">太阴病方（脾虚寒证） <a class="header-anchor" href="#太阴病方-脾虚寒证" aria-label="Permalink to &quot;太阴病方（脾虚寒证）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>理中丸</strong></td><td style="text-align:left;">人参、干姜、白术、甘草</td><td style="text-align:left;">太阴虚寒，腹满吐利</td><td style="text-align:left;">慢性胃肠炎</td></tr><tr><td style="text-align:left;"><strong>小建中汤</strong></td><td style="text-align:left;">桂枝汤+饴糖（倍芍药）</td><td style="text-align:left;">虚劳里急</td><td style="text-align:left;">胃痛、虚劳、痛经</td></tr></tbody></table><h3 id="少阴病方-虚衰证" tabindex="-1">少阴病方（虚衰证） <a class="header-anchor" href="#少阴病方-虚衰证" aria-label="Permalink to &quot;少阴病方（虚衰证）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>四逆汤</strong></td><td style="text-align:left;">附子、干姜、甘草</td><td style="text-align:left;">少阴寒化（脉微细、四肢厥逆）</td><td style="text-align:left;">心衰、休克</td></tr><tr><td style="text-align:left;"><strong>真武汤</strong></td><td style="text-align:left;">附子、茯苓、白术、白芍、生姜</td><td style="text-align:left;">少阴水气（水肿、心下悸）</td><td style="text-align:left;">慢性肾炎、心衰水肿</td></tr><tr><td style="text-align:left;"><strong>黄连阿胶汤</strong></td><td style="text-align:left;">黄连、黄芩、芍药、阿胶、鸡子黄</td><td style="text-align:left;">少阴热化（心烦不得眠）</td><td style="text-align:left;">失眠、焦虑</td></tr></tbody></table><h3 id="厥阴病方-寒热错杂" tabindex="-1">厥阴病方（寒热错杂） <a class="header-anchor" href="#厥阴病方-寒热错杂" aria-label="Permalink to &quot;厥阴病方（寒热错杂）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>乌梅丸</strong></td><td style="text-align:left;">乌梅、附子、干姜、黄连、黄柏等</td><td style="text-align:left;">厥阴病蛔厥</td><td style="text-align:left;">慢性结肠炎、寒热错杂</td></tr><tr><td style="text-align:left;"><strong>当归四逆汤</strong></td><td style="text-align:left;">当归、桂枝、细辛、通草、甘草</td><td style="text-align:left;">手足厥寒</td><td style="text-align:left;">冻疮、雷诺氏、脉管炎</td></tr></tbody></table><h3 id="其他经典方" tabindex="-1">其他经典方 <a class="header-anchor" href="#其他经典方" aria-label="Permalink to &quot;其他经典方&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>半夏泻心汤</strong></td><td style="text-align:left;">半夏、黄芩、干姜、人参、甘草、黄连、大枣</td><td style="text-align:left;">心下痞满，寒热错杂</td></tr><tr><td style="text-align:left;"><strong>炙甘草汤</strong></td><td style="text-align:left;">炙甘草、人参、生地、阿胶、麦冬、麻仁、桂枝、生姜、大枣</td><td style="text-align:left;">脉结代、心动悸</td></tr><tr><td style="text-align:left;"><strong>苓桂术甘汤</strong></td><td style="text-align:left;">茯苓、桂枝、白术、甘草</td><td style="text-align:left;">心下痰饮，胸胁支满</td></tr><tr><td style="text-align:left;"><strong>五苓散</strong></td><td style="text-align:left;">猪苓、泽泻、白术、茯苓、桂枝</td><td style="text-align:left;">膀胱蓄水，小便不利</td></tr><tr><td style="text-align:left;"><strong>桂枝茯苓丸</strong></td><td style="text-align:left;">桂枝、茯苓、丹皮、桃仁、芍药</td><td style="text-align:left;">瘀血内停，癥瘕积聚</td></tr></tbody></table><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><blockquote><p><strong>「上以疗君亲之疾，下以救贫贱之厄，中以保身长全，以养其生。」</strong>（自序）</p></blockquote><blockquote><p><strong>「虽未能尽愈诸病，庶可以见病知源，若能寻余所集，思过半矣。」</strong>（自序）</p></blockquote><blockquote><p><strong>「观其脉证，知犯何逆，随证治之。」</strong>（16条）</p></blockquote><blockquote><p><strong>「病人身大热，反欲得近衣者，热在皮肤，寒在骨髓也。」</strong>（11条）——辨真寒假热</p></blockquote><blockquote><p><strong>「病人身大寒，反不欲近衣者，寒在皮肤，热在骨髓也。」</strong>（11条）——辨真热假寒</p></blockquote><blockquote><p><strong>「凡厥者，阴阳气不相顺接，便为厥。」</strong>（337条）</p></blockquote><blockquote><p><strong>「阳明病，法多汗。」</strong>（182条）</p></blockquote><blockquote><p><strong>「少阴病，但欲寐。」</strong>（281条）</p></blockquote><blockquote><p><strong>「保胃气，存津液。」</strong>（治疗总则）</p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="黄元御与《伤寒论》" tabindex="-1">黄元御与《伤寒论》 <a class="header-anchor" href="#黄元御与《伤寒论》" aria-label="Permalink to &quot;黄元御与《伤寒论》&quot;">​</a></h3><p>黄元御著有《伤寒悬解》，以六经气化理论解释伤寒。他继承了仲景的六经体系，但更强调&quot;<strong>六经来自五脏</strong>&quot;，认为六经本质是脏腑气化的延伸。在此基础上构建了&quot;<strong>一气周流</strong>&quot;理论。</p><h3 id="彭子益-李可-与《伤寒论》" tabindex="-1">彭子益（李可）与《伤寒论》 <a class="header-anchor" href="#彭子益-李可-与《伤寒论》" aria-label="Permalink to &quot;彭子益（李可）与《伤寒论》&quot;">​</a></h3><p>彭子益在《圆运动的古中医学》中，用<strong>圆运动</strong>理论重新解释了《伤寒论》的所有经方，认为每个经方都是调整圆运动某一环节的失衡。李可继承此说，善用<strong>四逆汤类方</strong>破阴寒起沉疴。</p><h3 id="现代应用" tabindex="-1">现代应用 <a class="header-anchor" href="#现代应用" aria-label="Permalink to &quot;现代应用&quot;">​</a></h3><ul><li>经方派（&quot;方证对应&quot;派）直接取用原方</li><li>&quot;汤方辨证&quot;在临床各科广泛应用</li><li>日本汉方医学以《伤寒论》为核心</li></ul><hr><h2 id="六、与《黄帝内经》的关系" tabindex="-1">六、与《黄帝内经》的关系 <a class="header-anchor" href="#六、与《黄帝内经》的关系" aria-label="Permalink to &quot;六、与《黄帝内经》的关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">《黄帝内经》</th><th style="text-align:left;">《伤寒杂病论》</th></tr></thead><tbody><tr><td style="text-align:left;">定位</td><td style="text-align:left;">基础理论</td><td style="text-align:left;">临床实践</td></tr><tr><td style="text-align:left;">风格</td><td style="text-align:left;">原理阐释</td><td style="text-align:left;">辨证施治</td></tr><tr><td style="text-align:left;">方剂</td><td style="text-align:left;">仅载13方</td><td style="text-align:left;">载269方</td></tr><tr><td style="text-align:left;">辨证</td><td style="text-align:left;">理论框架</td><td style="text-align:left;">六经辨证体系</td></tr><tr><td style="text-align:left;">关系</td><td style="text-align:left;">仲景「撰用《素问》《九卷》……」</td><td style="text-align:left;"></td></tr></tbody></table><hr><p><em>本条目为精简框架版。六经各篇可独立扩展为专题，方剂可扩展为《伤寒论方剂速查》子条目。</em></p>',63)])])}const y=e(n,[["render",r]]);export{f as __pageData,y as default};
